 44→	private async resolveModelId(): Promise<void> {
 45→		try {
 46→			const modelId = await this.opensearchService.findDeployedModelId({
 47→				modelGroupName: MODEL_GROUP_NAME,
 48→			});
 49→
 50→			if (modelId && modelId !== this.modelId) {
 51→				const previousModelId = this.modelId;
 52→				this.modelId = modelId;
 53→				this.logger.log(`Model ID updated: ${previousModelId ?? 'none'} -> ${modelId}`);
 54→			} else if (!modelId) {
 55→				this.logger.warn(
 56→					'No deployed model found. Neural search will not work until bootstrap is run.',
 57→				);
 58→			}
